from spyne.application import Application
from spyne.decorator import rpc
from spyne.model.primitive import String, Float, Integer
from spyne.protocol.soap import Soap11
from spyne.server.wsgi import WsgiApplication
from spyne.service import ServiceBase
import logging
from wsgiref.simple_server import make_server

# Configure logging for better visibility
logging.basicConfig(level=logging.INFO)
logging.getLogger('spyne.protocol.soap').setLevel(logging.DEBUG) # Log SOAP specific details

# --- Mock Data Store (for demonstration purposes) ---
accounts_db = {
    "ACC001": {"holder": "Alice Smith", "balance": 1500.75, "currency": "USD"},
    "ACC002": {"holder": "Bob Johnson", "balance": 500.00, "currency": "USD"},
    "ACC003": {"holder": "Charlie Brown", "balance": 10000.50, "currency": "EUR"},
}
transaction_counter = 1000 # To generate unique transaction IDs

# --- Financial Service Definition ---
class FinancialService(ServiceBase):
    """
    A simple financial service providing account balance, fund transfer,
    and account information functionalities via SOAP.
    """
    SERVICE_URL_PATH = '/financial_api' # The URL path where the service will be exposed
    __service_name__ = 'FinancialService' # The name of the service in the WSDL

    @rpc(String, _returns=Float)
    def getBalance(ctx, account_id):
        """
        Retrieves the current balance for a given account.
        :param account_id: The unique identifier for the account.
        :return: The current balance of the account.
        """
        logging.info(f"getBalance called for account_id: {account_id}")
        account = accounts_db.get(account_id)
        if account:
            return account["balance"]
        else:
            # Spyne automatically converts Python exceptions to SOAP Faults
            logging.error(f"Account with ID {account_id} not found.")
            raise ValueError(f"Account with ID '{account_id}' not found.")

    @rpc(String, String, Float, _returns=(String, String))
    def transferFunds(ctx, source_account_id, destination_account_id, amount):
        """
        Transfers funds from a source account to a destination account.
        :param source_account_id: The ID of the account from which to transfer funds.
        :param destination_account_id: The ID of the account to which funds will be transferred.
        :param amount: The amount of funds to transfer.
        :return: A tuple containing the transaction ID and the status of the transfer (e.g., "SUCCESS" or "FAILED").
        """
        logging.info(
            f"transferFunds called: source={source_account_id}, dest={destination_account_id}, amount={amount}"
        )

        global transaction_counter
        transaction_id = f"TXN{transaction_counter:07d}"
        transaction_counter += 1

        source_acc = accounts_db.get(source_account_id)
        dest_acc = accounts_db.get(destination_account_id)

        if not source_acc:
            return transaction_id, f"FAILED: Source account '{source_account_id}' not found."
        if not dest_acc:
            return transaction_id, f"FAILED: Destination account '{destination_account_id}' not found."
        if amount <= 0:
            return transaction_id, "FAILED: Transfer amount must be positive."
        if source_acc["currency"] != dest_acc["currency"]:
            return transaction_id, "FAILED: Currency mismatch between accounts."
        if source_acc["balance"] < amount:
            return transaction_id, f"FAILED: Insufficient funds in source account '{source_account_id}'."

        # Simulate fund transfer
        source_acc["balance"] -= amount
        dest_acc["balance"] += amount

        logging.info(f"Transfer {transaction_id} successful.")
        return transaction_id, "SUCCESS"

    @rpc(String, _returns=(String, String, String))
    def getAccountInfo(ctx, account_id):
        """
        Retrieves detailed information for a given account.
        :param account_id: The unique identifier for the account.
        :return: A tuple containing the account holder's name, the account number (same as ID), and the currency.
        """
        logging.info(f"getAccountInfo called for account_id: {account_id}")
        account = accounts_db.get(account_id)
        if account:
            return account["holder"], account_id, account["currency"]
        else:
            logging.error(f"Account with ID {account_id} not found.")
            raise ValueError(f"Account with ID '{account_id}' not found.")

# --- Spyne Application Setup ---
# Create a Spyne Application instance.
# It registers the service, sets the target namespace (tns), and specifies
# the input/output protocols (SOAP 1.1 in this case).
soap_app = Application(
    [FinancialService],          # List of services to expose
    tns='urn:financialservices.example.com', # Target Namespace for the WSDL and SOAP operations
    in_protocol=Soap11(validator='lxml'), # Input protocol, using lxml for validation
    out_protocol=Soap11()        # Output protocol
)

# Wrap the Spyne application in a WSGI compliant application.
# This makes it compatible with standard Python WSGI servers.
wsgi_app = WsgiApplication(soap_app)

# --- Server Execution ---
if __name__ == '__main__':
    host = '0.0.0.0' # Listen on all available network interfaces
    port = 8000      # Port number

    print(f"Spyne SOAP server listening on http://{host}:{port}{FinancialService.SERVICE_URL_PATH}")
    print(f"WSDL available at http://{host}:{port}{FinancialService.SERVICE_URL_PATH}?wsdl")
    print("Press Ctrl+C to exit.")

    # Create and run a simple WSGI server
